args.sparql:
PREFIX wikibase: <http://wikiba.se/ontology#>
SELECT ?startTime ?endTime ?eventLabel WHERE {
  wd:Q48328 wdt:P571 ?time.
  ?time wikibase:timeStart ?startTime;
        wikibase:timeEnd ?endTime.
  OPTIONAL {
    wd:Q48328 wdt:P2041 ?event.
    ?event rdfs:label ?eventLabel.
    FILTER(LANG(?eventLabel) = "en").
  }
}

SELECT ?composition ?eventTime WHERE {
  wd:Q48328 wdt:P571/wikibase:timeValue ?composition.
  OPTIONAL {
    wd:Q48328 wdt:P2041/wikibase:timeValue ?eventTime.
  }
  FILTER(LANG(?composition) = 'en')
}

SELECT ?startTime ?endTime WHERE {
  wd:Q48328 wdt:P571 ?composition .
  ?composition wikibase:timeStart ?startTime ;
            wikibase:timeEnd ?endTime .
}

SELECT ?compTime WHERE {
  wd:Q48328 wdt:P571 ?comp_node .
  ?comp_node wikibase:timeValue ?compTime .
}

SELECT ?compositionTime ?eventPeriod WHERE {
  wd:Q48328 p:P571 ?compositionStatement .
  ?compositionStatement ps:P571 ?compositionValue ;
                     pq:P585 ?compositionTime .
  wd:Q48328 wdt:P2408 ?eventPeriod .
}

SELECT ?compYear ?period WHERE {
  wd:Q48328 wdt:P577 ?compYear .
  wd:Q48328 wdt:P2408 ?period .
}

SELECT ?compTime WHERE {
  wd:Q48328 p:P571 ?compStatement .
  ?compStatement ps:P571 ?compTime .
}
LIMIT 10

SELECT ?compStart ?compEnd ?eventStart ?eventEnd WHERE {
  # Composition dates
  wd:Q48328 p:P571 ?compositionStatement .
  ?compositionStatement pq:P580 ?compStart ;
                        pq:P582 ?compEnd .

  # Event period dates
  wd:Q48328 wdt:P2408 ?eventPeriod .
  ?eventPeriod wdt:P580 ?eventStart ;
             wdt:P582 ?eventEnd .
}

SELECT ?startTime ?endTime WHERE {
  wd:Q48328 p:P571 ?compStatement .
  ?compStatement pq:P580 ?startTime ;
                 pq:P582 ?endTime .
}
